7	
8	---------------------------------------------------------------------------------------------------
9	-- Description
10	---------------------------------------------------------------------------------------------------
11	-- This entity implements a decimating FIR filter. It supports multiple channels (time-division-
12	-- multiplexed). All channels share the same coefficient set. The filter taps are computed serially
13	-- (one tap per clock cycle) using a single multiplier.
14	--
15	-- Documentation:
16	-- https://github.com/open-logic/open-logic/blob/main/doc/fix/olo_fix_fir_dec_ser_chtdm.md
17	--
18	-- Note: The link points to the documentation of the latest release. If you
19	--       use an older version, the documentation might not match the code.
20	
21	---------------------------------------------------------------------------------------------------
22	-- Libraries
23	---------------------------------------------------------------------------------------------------
24	library ieee;
25	    use ieee.std_logic_1164.all;
26	    use ieee.numeric_std.all;
27	    use ieee.math_real.all;
28	
29	library work;
30	    use work.olo_base_pkg_math.all;
31	    use work.olo_base_pkg_array.all;
32	    use work.olo_base_pkg_string.all;
33	    use work.en_cl_fix_pkg.all;
34	    use work.olo_fix_pkg.all;
35	
36	---------------------------------------------------------------------------------------------------
37	-- Entity
38	---------------------------------------------------------------------------------------------------
39	entity olo_fix_fir_dec_ser_chtdm is
40	    generic (
41	        -- Formats
42	        InFmt_g           : string;
43	        OutFmt_g          : string;
44	        CoefFmt_g         : string;
45	        -- Filter parameters
46	        Channels_g        : positive;
47	        MaxRatio_g        : positive;
48	        MaxTaps_g         : positive;
49	        RuntimeCfg_g      : boolean  := false;
50	        -- Arithmetic
51	        GuardBits_g       : natural  := 1;
52	        Round_g           : string   := FixRound_Trunc_c;
53	        Saturate_g        : string   := FixSaturate_Warn_c;
54	        MultRegs_g        : positive := 1;
55	        -- Coefficient storage
56	        CoefInit_g        : string   := "0.0";
57	        CoefStorageType_g : string   := "ROM";
58	        CoefRamReadback_g : boolean  := false;
59	        CoefRamBehavior_g : string   := "RBW";
60	        CoefMemStyle_g    : string   := "auto";
61	        -- Data RAM
62	        DataRamBehavior_g : string   := "RBW";
63	        DataMemStyle_g    : string   := "auto"
64	    );
65	    port (
66	        -- Control Ports
67	        Clk              : in    std_logic;
68	        Rst              : in    std_logic;
69	        -- Runtime Config (only change during Rst = '1')
70	        Cfg_Ratio        : in    std_logic_vector(log2Ceil(MaxRatio_g) - 1 downto 0)             := toUslv(MaxRatio_g - 1, log2Ceil(MaxRatio_g));
71	        Cfg_Taps         : in    std_logic_vector(log2Ceil(MaxTaps_g) - 1 downto 0)              := toUslv(MaxTaps_g - 1, log2Ceil(MaxTaps_g));
72	        -- Coefficient Config Port
73	        Coef_Addr        : in    std_logic_vector(log2Ceil(MaxTaps_g) - 1 downto 0)              := (others => '0');
74	        Coef_WrEna       : in    std_logic                                                       := '0';
75	        Coef_WrData      : in    std_logic_vector(fixFmtWidthFromString(CoefFmt_g) - 1 downto 0) := (others => '0');
76	        Coef_RdEna       : in    std_logic                                                       := '0';
77	        Coef_RdData      : out   std_logic_vector(fixFmtWidthFromString(CoefFmt_g) - 1 downto 0);
78	        Coef_RdValid     : out   std_logic;
79	        -- Input
80	        In_Valid         : in    std_logic;
81	        In_Data          : in    std_logic_vector(fixFmtWidthFromString(InFmt_g) - 1 downto 0);
82	        In_Last          : in    std_logic                                                       := '0';
83	        -- Output
84	        Out_Valid        : out   std_logic;
85	        Out_Data         : out   std_logic_vector(fixFmtWidthFromString(OutFmt_g) - 1 downto 0);
86	        Out_Last         : out   std_logic
87	    );
88	end entity;
89	
90	---------------------------------------------------------------------------------------------------
91	-- Architecture
92	---------------------------------------------------------------------------------------------------
93	architecture rtl of olo_fix_fir_dec_ser_chtdm is
94	
95	    -- *** Entity Name ***
96	    constant EntityName_c : string := "olo_fix_fir_dec_ser_chtdm";
97	
98	    -- *** Formats ***
99	    constant InFmt_c   : FixFormat_t := cl_fix_format_from_string(InFmt_g);
100	    constant OutFmt_c  : FixFormat_t := cl_fix_format_from_string(OutFmt_g);
101	    constant CoefFmt_c : FixFormat_t := cl_fix_format_from_string(CoefFmt_g);
102	    constant MultFmt_c : FixFormat_t := cl_fix_mult_fmt(InFmt_c, CoefFmt_c);
103	    constant AccuFmt_c : FixFormat_t := (1, OutFmt_c.I + GuardBits_g, MultFmt_c.F);
104	
105	    -- *** Pipeline Stage Constant ***
106	    constant AccuStage_c : natural := 4 + MultRegs_g;
107	
108	    -- *** Memory Sizing ***
109	    constant DataMemDepthReq_c : natural := MaxTaps_g + MaxRatio_g;
110	    constant DataMemAddrBits_c : natural := log2Ceil(DataMemDepthReq_c);
111	    constant DataMemDepth_c    : natural := 2 ** DataMemAddrBits_c;
112	    constant CoefMemDepth_c    : natural := 2 ** log2Ceil(MaxTaps_g);
113	
114	    -- *** Types ***
115	    subtype InData_t   is std_logic_vector(fixFmtWidthFromString(InFmt_g) - 1 downto 0);
116	    subtype CoefData_t is std_logic_vector(fixFmtWidthFromString(CoefFmt_g) - 1 downto 0);
117	    subtype MultData_t is std_logic_vector(cl_fix_width(MultFmt_c) - 1 downto 0);
118	    subtype AccuData_t is std_logic_vector(cl_fix_width(AccuFmt_c) - 1 downto 0);
119	    subtype OutData_t  is std_logic_vector(fixFmtWidthFromString(OutFmt_g) - 1 downto 0);
120	
121	    type InData_a  is array (natural range <>) of InData_t;
122	    type ChNr_a    is array (natural range <>) of std_logic_vector(log2Ceil(Channels_g) - 1 downto 0);
123	
124	    -- *** Two Process Record ***
125	    type TwoProcess_r is record
126	        -- Stage 0
127	        Vld           : std_logic_vector(0 to 1);
128	        InSig         : InData_a(0 to 1);
129	        ChannelNr     : ChNr_a(0 to 3);
130	        FirstAfterRst : std_logic;
131	        -- Stage 1 state
132	        TapWrAddr     : std_logic_vector(DataMemAddrBits_c - 1 downto 0);
133	        Tap0Addr      : std_logic_vector(DataMemAddrBits_c - 1 downto 0);
134	        DecCnt        : std_logic_vector(log2Ceil(MaxRatio_g) - 1 downto 0);
135	        TapCnt        : std_logic_vector(log2Ceil(MaxTaps_g) - 1 downto 0);
136	        CalcChnl_1    : std_logic_vector(log2Ceil(Channels_g) - 1 downto 0);
137	        CalcChnl_2    : std_logic_vector(log2Ceil(Channels_g) - 1 downto 0);
138	        CalcChnl_3    : std_logic_vector(log2Ceil(Channels_g) - 1 downto 0);
139	        TapRdAddr_2   : std_logic_vector(DataMemAddrBits_c - 1 downto 0);
140	        CoefRdAddr_2  : std_logic_vector(log2Ceil(MaxTaps_g) - 1 downto 0);
141	        -- Pipeline control
142	        CalcOn        : std_logic_vector(1 to AccuStage_c);
143	        Last          : std_logic_vector(1 to AccuStage_c);
144	        First         : std_logic_vector(1 to AccuStage_c);
145	        -- Stage 3 / 4 state
146	        FirstTapLoop  : std_logic;
147	        TapRdAddr_3   : std_logic_vector(DataMemAddrBits_c - 1 downto 0);
148	        ReplaceZero   : std_logic;
149	        -- Stage 4: multiplier inputs
150	        MultInTap     : InData_t;
151	        MultInCoef    : CoefData_t;
152	        -- Accumulator
153	        Accu          : AccuData_t;
154	        AccuValid     : std_logic;
155	        -- Output channel counter
156	        OutChCnt      : natural range 0 to Channels_g - 1;
157	        Out_Valid     : std_logic;
158	        Out_Last      : std_logic;
159	        Out_Data      : OutData_t;
160	    end record;
161	
162	    signal r, r_next : TwoProcess_r;
163	
164	    -- *** Component Connection Signals ***
165	    signal DataRamWrAddr : std_logic_vector(DataMemAddrBits_c + log2Ceil(Channels_g) - 1 downto 0);
166	    signal DataRamRdAddr : std_logic_vector(DataMemAddrBits_c + log2Ceil(Channels_g) - 1 downto 0);
167	    signal DataRamDout_3 : InData_t;
168	    signal CoefRamDout_3 : CoefData_t;
169	    signal MultOut_Data  : MultData_t;
170	    signal MultOut_Valid : std_logic;
171	    signal ResizeData    : OutData_t;
172	    signal ResizeValid   : std_logic;
173	
174	    -- *** Runtime Config Signals ***
175	    signal Cfg_Taps_I  : std_logic_vector(Cfg_Taps'range);
176	    signal Cfg_Ratio_I : std_logic_vector(Cfg_Ratio'range);
177	
178	begin
179	
180	    -- Runtime configurability
181	    Cfg_Taps_I  <= Cfg_Taps when RuntimeCfg_g else toUslv(MaxTaps_g - 1, Cfg_Taps_I'length);
182	    Cfg_Ratio_I <= Cfg_Ratio when RuntimeCfg_g else toUslv(MaxRatio_g - 1, Cfg_Ratio_I'length);
183	
184	    -----------------------------------------------------------------------------------------------
185	    -- Assertions
186	    -----------------------------------------------------------------------------------------------
187	    -- synthesis translate_off
188	    assert Channels_g >= 2
189	        report errorMessage(EntityName_c, "Channels_g must be >= 2. For single-channel use a non-TDM variant.")
190	        severity error;
191	    assert MaxRatio_g >= 2
192	        report errorMessage(EntityName_c, "MaxRatio_g must be >= 2.")
193	        severity error;
194	    assert MaxTaps_g >= 2
195	        report errorMessage(EntityName_c, "MaxTaps_g must be >= 2.")
196	        severity error;
197	    -- synthesis translate_on
198	
199	    -----------------------------------------------------------------------------------------------
200	    -- Combinatorial Process
201	    -----------------------------------------------------------------------------------------------
202	    p_comb : process (all) is
203	        variable v        : TwoProcess_r;
204	        variable AccuIn_v : AccuData_t;
205	    begin
206	        v := r;
207	
208	        -- *** Pipe Handling ***
209	        v.Vld(1)                   := r.Vld(0);
210	        v.InSig(1)                 := r.InSig(0);
211	        v.ChannelNr(1 to 3)        := r.ChannelNr(0 to 2);
212	        v.CalcOn(2 to AccuStage_c) := r.CalcOn(1 to AccuStage_c - 1);
213	        v.Last(2 to AccuStage_c)   := r.Last(1 to AccuStage_c - 1);
214	        v.First(2 to AccuStage_c)  := r.First(1 to AccuStage_c - 1);
215	
216	        -- *** Stage 0: Input Register ***
217	        v.Vld(0)   := In_Valid;
218	        v.InSig(0) := In_Data;
219	
220	        if In_Valid = '1' then
221	            if unsigned(r.ChannelNr(0)) = Channels_g - 1 or r.FirstAfterRst = '1' then
222	                v.ChannelNr(0)  := (others => '0');
223	                v.FirstAfterRst := '0';
224	            else
225	                v.ChannelNr(0) := std_logic_vector(unsigned(r.ChannelNr(0)) + 1);
226	            end if;
227	        end if;
228	
229	        -- *** Stage 1: Data RAM Write, Decimation & Calculation Control ***
230	        -- Advance tap write address when last channel's sample arrives
231	        if (r.Vld(1) = '1') and (unsigned(r.ChannelNr(1)) = Channels_g - 1) then
232	            v.TapWrAddr := std_logic_vector(unsigned(r.TapWrAddr) + 1);
233	        end if;
234	
235	        -- Tap count decrement
236	        v.First(1) := '0';
237	        v.Last(1)  := '0';
238	        v.TapCnt   := std_logic_vector(unsigned(r.TapCnt) - 1);
239	
240	        -- Last tap of a channel
241	        if unsigned(r.TapCnt) = 1 or unsigned(Cfg_Taps_I) = 0 then
242	            v.Last(1) := '1';
243	        end if;
244	
245	        -- Move to next channel or finish calculation
246	        if unsigned(r.TapCnt) = 0 then
247	            if unsigned(r.CalcChnl_1) = Channels_g - 1 then
248	                v.CalcOn(1) := '0';
249	            else
250	                v.First(1)   := '1';
251	                v.CalcChnl_1 := std_logic_vector(unsigned(r.CalcChnl_1) + 1);
252	                v.TapCnt     := Cfg_Taps_I;
253	            end if;
254	        end if;
255	
256	        -- Start new calculation when all channels' input samples have arrived
257	        if r.Vld(0) = '1' then
258	            if unsigned(r.ChannelNr(0)) = Channels_g - 1 then
259	                if unsigned(r.DecCnt) = 0 then
260	                    v.Tap0Addr   := r.TapWrAddr;
261	                    v.TapCnt     := Cfg_Taps_I;
262	                    v.CalcOn(1)  := '1';
263	                    v.First(1)   := '1';
264	                    v.CalcChnl_1 := (others => '0');
265	                    v.DecCnt     := Cfg_Ratio_I;
266	                    -- The idle TapCnt countdown may have set Last(1) spuriously because it is freerunning. We clear
267	                    -- it in case it would be on by incident.
268	                    v.Last(1) := '0';
269	                else
270	                    v.DecCnt := std_logic_vector(unsigned(r.DecCnt) - 1);
271	                end if;
272	            end if;
273	        end if;
274	
275	        -- *** Stage 2: Address Calculation ***
276	        v.CalcChnl_2   := r.CalcChnl_1;
277	        v.TapRdAddr_2  := std_logic_vector(unsigned(r.Tap0Addr) - unsigned(r.TapCnt));
278	        v.CoefRdAddr_2 := r.TapCnt;
279	
280	        -- *** Stage 3: Pipeline TapRdAddr and CalcChnl (RAM data arrives next cycle) ***
281	        v.TapRdAddr_3 := r.TapRdAddr_2;
282	        v.CalcChnl_3  := r.CalcChnl_2;
283	
284	        -- *** Stage 4: Multiplier Input MUX with ReplaceZero ***
285	        -- Replace unwritten RAM locations with zeros for bit-trueness at startup
286	        if r.ReplaceZero = '0' or unsigned(r.TapRdAddr_3) <= unsigned(Cfg_Ratio_I) then
287	            v.MultInTap := DataRamDout_3;
288	        else
289	            v.MultInTap := (others => '0');
290	        end if;
291	
292	        -- Track when zero-replacement can be disabled
293	        -- CalcChnl_3 is used (not ChannelNr) so the check works regardless of input stalls
294	        if r.FirstTapLoop = '0' then
295	            v.ReplaceZero := '0';
296	        elsif r.CalcOn(3) = '1' then
297	            if r.First(3) = '1' and unsigned(r.TapRdAddr_3) <= unsigned(Cfg_Ratio_I) then
298	                v.ReplaceZero := '0';
299	                if unsigned(r.CalcChnl_3) = Channels_g - 1 then
300	                    v.FirstTapLoop := '0';
301	                end if;
302	            elsif r.Last(3) = '1' then
303	                v.ReplaceZero := '1';
304	            elsif unsigned(r.TapRdAddr_3) = 0 then
305	                v.ReplaceZero := '0';
306	            end if;
307	        end if;
308	
309	        v.MultInCoef := CoefRamDout_3;
310	
311	        -- *** Stage AccuStage_c: Accumulate ***
312	        if r.First(AccuStage_c) = '1' then
313	            AccuIn_v := (others => '0');
314	        else
315	            AccuIn_v := r.Accu;
316	        end if;
317	        v.Accu := cl_fix_add(MultOut_Data, MultFmt_c,
318	                             AccuIn_v, AccuFmt_c,
319	                             AccuFmt_c, Trunc_s, None_s);
320	
321	        -- Capture when last tap of a channel's calculation is done
322	        v.AccuValid := r.Last(AccuStage_c) and r.CalcOn(AccuStage_c);
323	
324	        -- *** Output: capture result from olo_fix_resize ***
325	        v.Out_Valid := '0';
326	        v.Out_Last  := '0';
327	        if ResizeValid = '1' then
328	            v.Out_Valid := '1';
329	            v.Out_Data  := ResizeData;
330	            if r.OutChCnt = Channels_g - 1 then
331	                v.Out_Last := '1';
332	                v.OutChCnt := 0;
333	            else
334	                v.OutChCnt := r.OutChCnt + 1;
335	            end if;
336	        end if;
337	
338	        r_next <= v;
339	    end process;
340	
341	    -----------------------------------------------------------------------------------------------
342	    -- Output Assignment
343	    -----------------------------------------------------------------------------------------------
344	    Out_Valid <= r.Out_Valid;
345	    Out_Data  <= r.Out_Data;
346	    Out_Last  <= r.Out_Last;
347	
348	    -----------------------------------------------------------------------------------------------
349	    -- Sequential Process
350	    -----------------------------------------------------------------------------------------------
351	    p_seq : process (Clk) is
352	    begin
353	        if rising_edge(Clk) then
354	            r <= r_next;
355	            if Rst = '1' then
356	                r.FirstAfterRst <= '1';
357	                r.Vld           <= (others => '0');
358	                r.ChannelNr(0)  <= (others => '0');
359	                r.CalcChnl_1    <= (others => '0');
360	                r.TapWrAddr     <= (others => '0');
361	                r.DecCnt        <= (others => '0');
362	                r.CalcOn        <= (others => '0');
363	                r.Last          <= (others => '0');
364	                r.First         <= (others => '0');
365	                r.AccuValid     <= '0';
366	                r.Out_Valid     <= '0';
367	                r.Out_Last      <= '0';
368	                r.ReplaceZero   <= '1';
369	                r.FirstTapLoop  <= '1';
370	                r.OutChCnt      <= 0;
371	                r.TapCnt        <= Cfg_Taps_I;
372	            end if;
373	        end if;
374	    end process;
375	
376	    -----------------------------------------------------------------------------------------------
377	    -- Input TDM Validation
378	    -----------------------------------------------------------------------------------------------
379	    -- synthesis translate_off
380	    p_assert_in : process (Clk) is
381	        variable ChCnt_v : natural range 0 to Channels_g - 1;
382	    begin
383	        if rising_edge(Clk) then
384	            if Rst = '1' then
385	                ChCnt_v := 0;
386	            elsif In_Valid = '1' then
387	
388	                -- Check Tap Count > 1
389	                assert unsigned(Cfg_Taps) >= 1 or RuntimeCfg_g = false
390	                    report errorMessage(EntityName_c, "Cfg_Taps must be >= 0 (1 tap filter is not supported)")
391	                    severity error;
392	
393	                -- Check TDM Timing
394	                if In_Last = '1' then
395	                    assert ChCnt_v = Channels_g - 1
396	                        report errorMessage(EntityName_c, "In_Last asserted at channel index " &
397	                               integer'image(ChCnt_v) & " but expected at " &
398	                               integer'image(Channels_g - 1))
399	                        severity error;
400	                end if;
401	                if ChCnt_v = Channels_g - 1 then
402	                    ChCnt_v := 0;
403	                else
404	                    ChCnt_v := ChCnt_v + 1;
405	                end if;
406	            end if;
407	        end if;
408	    end process;
409	
410	    -- synthesis translate_on
411	
412	    -----------------------------------------------------------------------------------------------
413	    -- Component Instantiations
414	    -----------------------------------------------------------------------------------------------
415	    -- *** Multiplier ***
416	    i_mult : entity work.olo_fix_mult
417	        generic map (
418	            AFmt_g      => InFmt_g,
419	            BFmt_g      => CoefFmt_g,
420	            ResultFmt_g => to_string(MultFmt_c),
421	            Round_g     => FixRound_Trunc_c,
422	            Saturate_g  => FixSaturate_None_c,
423	            OpRegs_g    => MultRegs_g,
424	            RoundReg_g  => "NO",
425	            SatReg_g    => "NO"
426	        )
427	        port map (
428	            Clk        => Clk,
429	            Rst        => Rst,
430	            In_Valid   => r.CalcOn(4),
431	            In_A       => r.MultInTap,
432	            In_B       => r.MultInCoef,
433	            Out_Valid  => MultOut_Valid,
434	            Out_Result => MultOut_Data
435	        );
436	
437	    -- *** Output Resize (round + saturate accumulator to output format) ***
438	    i_resize : entity work.olo_fix_resize
439	        generic map (
440	            AFmt_g      => to_string(AccuFmt_c),
441	            ResultFmt_g => OutFmt_g,
442	            Round_g     => Round_g,
443	            Saturate_g  => Saturate_g,
444	            RoundReg_g  => "YES",
445	            SatReg_g    => "YES"
446	        )
447	        port map (
448	            Clk        => Clk,
449	            Rst        => Rst,
450	            In_Valid   => r.AccuValid,
451	            In_A       => r.Accu,
452	            Out_Valid  => ResizeValid,
453	            Out_Result => ResizeData
454	        );
455	
456	    -- *** Coefficient Storage ***
457	    i_coef : entity work.olo_fix_coef_storage
458	        generic map (
459	            Depth_g       => CoefMemDepth_c,
460	            Fmt_g         => CoefFmt_g,
461	            Init_g        => CoefInit_g,
462	            StorageType_g => CoefStorageType_g,
463	            RamReadback_g => CoefRamReadback_g,
464	            RamBehavior_g => CoefRamBehavior_g,
465	            RdLatency_g   => 1,
466	            MemStyle_g    => CoefMemStyle_g
467	        )
468	        port map (
469	            Clk          => Clk,
470	            Rst          => Rst,
471	            Cfg_Addr     => Coef_Addr,
472	            Cfg_WrEna    => Coef_WrEna,
473	            Cfg_WrData   => Coef_WrData,
474	            Cfg_RdEna    => Coef_RdEna,
475	            Cfg_RdData   => Coef_RdData,
476	            Cfg_RdValid  => Coef_RdValid,
477	            Coef_Addr    => r.CoefRdAddr_2,
478	            Coef_RdEna   => '1',
479	            Coef_RdData  => CoefRamDout_3,
480	            Coef_RdValid => open
481	        );
482	
483	    -- *** Data RAM (Simple Dual Port: one write port, one read port) ***
484	    DataRamWrAddr <= r.ChannelNr(1) & r.TapWrAddr;
485	    DataRamRdAddr <= r.CalcChnl_2 & r.TapRdAddr_2;
486	
487	    i_data_ram : entity work.olo_base_ram_sdp
488	        generic map (
489	            Depth_g       => DataMemDepth_c * Channels_g,
490	            Width_g       => fixFmtWidthFromString(InFmt_g),
491	            RdLatency_g   => 1,
492	            RamStyle_g    => DataMemStyle_g,
493	            RamBehavior_g => DataRamBehavior_g
494	        )
495	        port map (
496	            Clk     => Clk,
497	            Rst     => Rst,
498	            Wr_Addr => DataRamWrAddr,
499	            Wr_Ena  => r.Vld(1),
500	            Wr_Data => r.InSig(1),
501	            Rd_Addr => DataRamRdAddr,
502	            Rd_Ena  => '1',
503	            Rd_Data => DataRamDout_3
504	        );
505	
506	end architecture;
507

