8	---------------------------------------------------------------------------------------------------
9	-- Description
10	---------------------------------------------------------------------------------------------------
11	-- This entity implements a decimating FIR filter. It supports multiple channels that are processed
12	-- in parallel (all channel samples arrive in the same clock cycle, concatenated into one wide
13	-- vector). All channels share the same coefficient set. The filter taps are computed serially
14	-- (one tap per clock cycle) using one multiplier per channel.
15	--
16	-- Documentation:
17	-- https://github.com/open-logic/open-logic/blob/main/doc/fix/olo_fix_fir_dec_ser_chpar.md
18	--
19	-- Note: The link points to the documentation of the latest release. If you
20	--       use an older version, the documentation might not match the code.
21	
22	---------------------------------------------------------------------------------------------------
23	-- Libraries
24	---------------------------------------------------------------------------------------------------
25	library ieee;
26	    use ieee.std_logic_1164.all;
27	    use ieee.numeric_std.all;
28	    use ieee.math_real.all;
29	
30	library work;
31	    use work.olo_base_pkg_math.all;
32	    use work.olo_base_pkg_array.all;
33	    use work.olo_base_pkg_string.all;
34	    use work.en_cl_fix_pkg.all;
35	    use work.olo_fix_pkg.all;
36	
37	---------------------------------------------------------------------------------------------------
38	-- Entity
39	---------------------------------------------------------------------------------------------------
40	entity olo_fix_fir_dec_ser_chpar is
41	    generic (
42	        -- Formats
43	        InFmt_g           : string;
44	        OutFmt_g          : string;
45	        CoefFmt_g         : string;
46	        -- Filter parameters
47	        Channels_g        : positive;
48	        MaxRatio_g        : positive;
49	        MaxTaps_g         : positive;
50	        RuntimeCfg_g      : boolean  := false;
51	        -- Arithmetic
52	        GuardBits_g       : natural  := 1;
53	        Round_g           : string   := FixRound_Trunc_c;
54	        Saturate_g        : string   := FixSaturate_Warn_c;
55	        MultRegs_g        : positive := 1;
56	        -- Coefficient storage
57	        CoefInit_g        : string   := "0.0";
58	        CoefStorageType_g : string   := "ROM";
59	        CoefRamReadback_g : boolean  := false;
60	        CoefRamBehavior_g : string   := "RBW";
61	        CoefMemStyle_g    : string   := "auto";
62	        -- Data RAM
63	        DataRamBehavior_g : string   := "RBW";
64	        DataMemStyle_g    : string   := "auto"
65	    );
66	    port (
67	        -- Control Ports
68	        Clk          : in    std_logic;
69	        Rst          : in    std_logic;
70	        -- Runtime Config (only change during Rst = '1')
71	        Cfg_Ratio    : in    std_logic_vector(log2Ceil(MaxRatio_g) - 1 downto 0)             := toUslv(MaxRatio_g - 1, log2Ceil(MaxRatio_g));
72	        Cfg_Taps     : in    std_logic_vector(log2Ceil(MaxTaps_g) - 1 downto 0)              := toUslv(MaxTaps_g - 1, log2Ceil(MaxTaps_g));
73	        -- Coefficient Config Port
74	        Coef_Addr    : in    std_logic_vector(log2Ceil(MaxTaps_g) - 1 downto 0)              := (others => '0');
75	        Coef_WrEna   : in    std_logic                                                       := '0';
76	        Coef_WrData  : in    std_logic_vector(fixFmtWidthFromString(CoefFmt_g) - 1 downto 0) := (others => '0');
77	        Coef_RdEna   : in    std_logic                                                       := '0';
78	        Coef_RdData  : out   std_logic_vector(fixFmtWidthFromString(CoefFmt_g) - 1 downto 0);
79	        Coef_RdValid : out   std_logic;
80	        -- Input (all channels concatenated, channel 0 in the LSBs)
81	        In_Valid     : in    std_logic;
82	        In_Data      : in    std_logic_vector(fixFmtWidthFromString(InFmt_g) * Channels_g - 1 downto 0);
83	        -- Output (all channels concatenated, channel 0 in the LSBs)
84	        Out_Valid    : out   std_logic;
85	        Out_Data     : out   std_logic_vector(fixFmtWidthFromString(OutFmt_g) * Channels_g - 1 downto 0)
86	    );
87	end entity;
88	
89	---------------------------------------------------------------------------------------------------
90	-- Architecture
91	---------------------------------------------------------------------------------------------------
92	architecture rtl of olo_fix_fir_dec_ser_chpar is
93	
94	    -- *** Entity Name ***
95	    constant EntityName_c : string := "olo_fix_fir_dec_ser_chpar";
96	
97	    -- *** Formats ***
98	    constant InFmt_c   : FixFormat_t := cl_fix_format_from_string(InFmt_g);
99	    constant OutFmt_c  : FixFormat_t := cl_fix_format_from_string(OutFmt_g);
100	    constant CoefFmt_c : FixFormat_t := cl_fix_format_from_string(CoefFmt_g);
101	    constant MultFmt_c : FixFormat_t := cl_fix_mult_fmt(InFmt_c, CoefFmt_c);
102	    constant AccuFmt_c : FixFormat_t := (1, OutFmt_c.I + GuardBits_g, MultFmt_c.F);
103	
104	    -- *** Port Widths ***
105	    constant InWidth_c  : natural := fixFmtWidthFromString(InFmt_g);
106	    constant OutWidth_c : natural := fixFmtWidthFromString(OutFmt_g);
107	
108	    -- *** Pipeline Stage Constant ***
109	    constant AccuStage_c : natural := 4 + MultRegs_g;
110	
111	    -- *** Memory Sizing ***
112	    constant DataMemDepthReq_c : natural := MaxTaps_g + MaxRatio_g;
113	    constant DataMemAddrBits_c : natural := log2Ceil(DataMemDepthReq_c);
114	    constant DataMemDepth_c    : natural := 2 ** DataMemAddrBits_c;
115	    constant CoefMemDepth_c    : natural := 2 ** log2Ceil(MaxTaps_g);
116	
117	    -- *** Types ***
118	    subtype InData_t   is std_logic_vector(InWidth_c - 1 downto 0);
119	    subtype CoefData_t is std_logic_vector(fixFmtWidthFromString(CoefFmt_g) - 1 downto 0);
120	    subtype MultData_t is std_logic_vector(cl_fix_width(MultFmt_c) - 1 downto 0);
121	    subtype AccuData_t is std_logic_vector(cl_fix_width(AccuFmt_c) - 1 downto 0);
122	    subtype OutData_t  is std_logic_vector(OutWidth_c - 1 downto 0);
123	    subtype InWide_t   is std_logic_vector(InWidth_c * Channels_g - 1 downto 0);
124	
125	    type InWide_a  is array (natural range <>) of InWide_t;
126	    type ChVec_t   is array (0 to Channels_g - 1) of InData_t;
127	    type AccuVec_t is array (0 to Channels_g - 1) of AccuData_t;
128	    type MultVec_t is array (0 to Channels_g - 1) of MultData_t;
129	    type OutVec_t  is array (0 to Channels_g - 1) of OutData_t;
130	
131	    -- *** Two Process Record ***
132	    type TwoProcess_r is record
133	        -- Stage 0
134	        Vld          : std_logic_vector(0 to 1);
135	        InSig        : InWide_a(0 to 1);
136	        -- Stage 1 state
137	        TapWrAddr    : std_logic_vector(DataMemAddrBits_c - 1 downto 0);
138	        Tap0Addr     : std_logic_vector(DataMemAddrBits_c - 1 downto 0);
139	        DecCnt       : std_logic_vector(log2Ceil(MaxRatio_g) - 1 downto 0);
140	        TapCnt       : std_logic_vector(log2Ceil(MaxTaps_g) - 1 downto 0);
141	        -- Stage 2 state
142	        TapRdAddr_2  : std_logic_vector(DataMemAddrBits_c - 1 downto 0);
143	        CoefRdAddr_2 : std_logic_vector(log2Ceil(MaxTaps_g) - 1 downto 0);
144	        -- Pipeline control
145	        CalcOn       : std_logic_vector(1 to AccuStage_c);
146	        Last         : std_logic_vector(1 to AccuStage_c);
147	        First        : std_logic_vector(1 to AccuStage_c);
148	        -- Stage 3 state
149	        FirstTapLoop : std_logic;
150	        TapRdAddr_3  : std_logic_vector(DataMemAddrBits_c - 1 downto 0);
151	        ReplaceZero  : std_logic;
152	        -- Stage 4: multiplier inputs
153	        MultInTap    : ChVec_t;
154	        MultInCoef   : CoefData_t;
155	        -- Accumulator
156	        Accu         : AccuVec_t;
157	        AccuValid    : std_logic;
158	    end record;
159	
160	    signal r, r_next : TwoProcess_r;
161	
162	    -- *** Component Connection Signals ***
163	    signal DataRamDout_3  : InWide_t;
164	    signal CoefRamDout_3  : CoefData_t;
165	    signal MultOut_Data   : MultVec_t;
166	    signal ResizeData     : OutVec_t;
167	    signal ResizeValidVec : std_logic_vector(0 to Channels_g - 1);
168	    signal ResizeValid    : std_logic;
169	
170	    -- *** Runtime Config Signals ***
171	    signal Cfg_Taps_I  : std_logic_vector(Cfg_Taps'range);
172	    signal Cfg_Ratio_I : std_logic_vector(Cfg_Ratio'range);
173	
174	begin
175	
176	    -- Runtime configurability
177	    Cfg_Taps_I  <= Cfg_Taps when RuntimeCfg_g else toUslv(MaxTaps_g - 1, Cfg_Taps_I'length);
178	    Cfg_Ratio_I <= Cfg_Ratio when RuntimeCfg_g else toUslv(MaxRatio_g - 1, Cfg_Ratio_I'length);
179	
180	    -----------------------------------------------------------------------------------------------
181	    -- Assertions
182	    -----------------------------------------------------------------------------------------------
183	    -- synthesis translate_off
184	    assert MaxTaps_g >= 2
185	        report errorMessage(EntityName_c, "MaxTaps_g must be >= 2.")
186	        severity error;
187	    -- synthesis translate_on
188	
189	    -----------------------------------------------------------------------------------------------
190	    -- Combinatorial Process
191	    -----------------------------------------------------------------------------------------------
192	    p_comb : process (all) is
193	        variable v        : TwoProcess_r;
194	        variable AccuIn_v : AccuData_t;
195	    begin
196	        v := r;
197	
198	        -- *** Pipe Handling ***
199	        v.Vld(1)                   := r.Vld(0);
200	        v.InSig(1)                 := r.InSig(0);
201	        v.CalcOn(2 to AccuStage_c) := r.CalcOn(1 to AccuStage_c - 1);
202	        v.Last(2 to AccuStage_c)   := r.Last(1 to AccuStage_c - 1);
203	        v.First(2 to AccuStage_c)  := r.First(1 to AccuStage_c - 1);
204	
205	        -- *** Stage 0: Input Register ***
206	        v.Vld(0)   := In_Valid;
207	        v.InSig(0) := In_Data;
208	
209	        -- *** Stage 1: Data RAM Write, Decimation & Calculation Control ***
210	        -- Advance tap write address when a new sample set was written
211	        if r.Vld(1) = '1' then
212	            v.TapWrAddr := std_logic_vector(unsigned(r.TapWrAddr) + 1);
213	        end if;
214	
215	        -- Tap count decrement (guarded so it idles at zero)
216	        v.First(1) := '0';
217	        v.Last(1)  := '0';
218	        if unsigned(r.TapCnt) /= 0 then
219	            v.TapCnt := std_logic_vector(unsigned(r.TapCnt) - 1);
220	        else
221	            v.CalcOn(1) := '0';
222	        end if;
223	
224	        -- Last tap of the calculation
225	        if unsigned(r.TapCnt) = 1 or unsigned(Cfg_Taps_I) = 0 then
226	            v.Last(1) := '1';
227	        end if;
228	
229	        -- Start new calculation when a sample set arrives and the decimation phase elapsed
230	        if r.Vld(0) = '1' then
231	            if unsigned(r.DecCnt) = 0 then
232	                v.Tap0Addr  := r.TapWrAddr;
233	                v.TapCnt    := Cfg_Taps_I;
234	                v.CalcOn(1) := '1';
235	                v.First(1)  := '1';
236	                v.DecCnt    := Cfg_Ratio_I;
237	            else
238	                v.DecCnt := std_logic_vector(unsigned(r.DecCnt) - 1);
239	            end if;
240	        end if;
241	
242	        -- *** Stage 2: Address Calculation ***
243	        v.TapRdAddr_2  := std_logic_vector(unsigned(r.Tap0Addr) - unsigned(r.TapCnt));
244	        v.CoefRdAddr_2 := r.TapCnt;
245	
246	        -- *** Stage 3: Pipeline TapRdAddr (RAM data arrives next cycle) ***
247	        v.TapRdAddr_3 := r.TapRdAddr_2;
248	
249	        -- *** Stage 4: Multiplier Input MUX with ReplaceZero ***
250	        -- Replace unwritten RAM locations with zeros for bit-trueness at startup
251	        for i in 0 to Channels_g - 1 loop
252	            if r.ReplaceZero = '0' or unsigned(r.TapRdAddr_3) <= unsigned(Cfg_Ratio_I) then
253	                v.MultInTap(i) := DataRamDout_3(InWidth_c * (i + 1) - 1 downto InWidth_c * i);
254	            else
255	                v.MultInTap(i) := (others => '0');
256	            end if;
257	        end loop;
258	
259	        -- Track when zero-replacement can be disabled
260	        if r.FirstTapLoop = '0' then
261	            v.ReplaceZero := '0';
262	        elsif r.CalcOn(3) = '1' then
263	            if r.First(3) = '1' and unsigned(r.TapRdAddr_3) <= unsigned(Cfg_Ratio_I) then
264	                v.ReplaceZero  := '0';
265	                v.FirstTapLoop := '0';
266	            elsif r.Last(3) = '1' then
267	                v.ReplaceZero := '1';
268	            elsif unsigned(r.TapRdAddr_3) = 0 then
269	                v.ReplaceZero := '0';
270	            end if;
271	        end if;
272	
273	        v.MultInCoef := CoefRamDout_3;
274	
275	        -- *** Stage AccuStage_c: Accumulate (one accumulator per channel) ***
276	        for i in 0 to Channels_g - 1 loop
277	            if r.First(AccuStage_c) = '1' then
278	                AccuIn_v := (others => '0');
279	            else
280	                AccuIn_v := r.Accu(i);
281	            end if;
282	            v.Accu(i) := cl_fix_add(MultOut_Data(i), MultFmt_c,
283	                                    AccuIn_v, AccuFmt_c,
284	                                    AccuFmt_c, Trunc_s, None_s);
285	        end loop;
286	
287	        -- Capture when the last tap of the calculation is done
288	        v.AccuValid := r.Last(AccuStage_c) and r.CalcOn(AccuStage_c);
289	
290	        r_next <= v;
291	    end process;
292	
293	    -----------------------------------------------------------------------------------------------
294	    -- Output Assignment
295	    -----------------------------------------------------------------------------------------------
296	    -- All channel resize instances share the same timing, channel 0 provides the valid
297	    ResizeValid <= ResizeValidVec(0);
298	    Out_Valid   <= ResizeValid;
299	
300	    g_out : for i in 0 to Channels_g - 1 generate
301	        Out_Data(OutWidth_c * (i + 1) - 1 downto OutWidth_c * i) <= ResizeData(i);
302	    end generate;
303	
304	    -----------------------------------------------------------------------------------------------
305	    -- Sequential Process
306	    -----------------------------------------------------------------------------------------------
307	    p_seq : process (Clk) is
308	    begin
309	        if rising_edge(Clk) then
310	            r <= r_next;
311	            if Rst = '1' then
312	                r.Vld          <= (others => '0');
313	                r.TapWrAddr    <= (others => '0');
314	                r.DecCnt       <= (others => '0');
315	                r.TapCnt       <= (others => '0');
316	                r.CalcOn       <= (others => '0');
317	                r.Last         <= (others => '0');
318	                r.First        <= (others => '0');
319	                r.AccuValid    <= '0';
320	                r.ReplaceZero  <= '1';
321	                r.FirstTapLoop <= '1';
322	            end if;
323	        end if;
324	    end process;
325	
326	    -----------------------------------------------------------------------------------------------
327	    -- Configuration Assertions
328	    -----------------------------------------------------------------------------------------------
329	    -- synthesis translate_off
330	    p_assert_cfg : process (Clk) is
331	    begin
332	        if rising_edge(Clk) then
333	            if Rst = '0' and In_Valid = '1' then
334	                assert unsigned(Cfg_Taps) >= 1 or RuntimeCfg_g = false
335	                    report errorMessage(EntityName_c, "Cfg_Taps must be >= 1 (1 tap filter is not supported)")
336	                    severity error;
337	            end if;
338	        end if;
339	    end process;
340	
341	    -- synthesis translate_on
342	
343	    -----------------------------------------------------------------------------------------------
344	    -- Component Instantiations
345	    -----------------------------------------------------------------------------------------------
346	    -- *** Coefficient Storage (shared by all channels) ***
347	    i_coef : entity work.olo_fix_coef_storage
348	        generic map (
349	            Depth_g       => CoefMemDepth_c,
350	            Fmt_g         => CoefFmt_g,
351	            Init_g        => CoefInit_g,
352	            StorageType_g => CoefStorageType_g,
353	            RamReadback_g => CoefRamReadback_g,
354	            RamBehavior_g => CoefRamBehavior_g,
355	            RdLatency_g   => 1,
356	            MemStyle_g    => CoefMemStyle_g
357	        )
358	        port map (
359	            Clk          => Clk,
360	            Rst          => Rst,
361	            Cfg_Addr     => Coef_Addr,
362	            Cfg_WrEna    => Coef_WrEna,
363	            Cfg_WrData   => Coef_WrData,
364	            Cfg_RdEna    => Coef_RdEna,
365	            Cfg_RdData   => Coef_RdData,
366	            Cfg_RdValid  => Coef_RdValid,
367	            Coef_Addr    => r.CoefRdAddr_2,
368	            Coef_RdEna   => '1',
369	            Coef_RdData  => CoefRamDout_3,
370	            Coef_RdValid => open
371	        );
372	
373	    -- *** Data RAM (Simple Dual Port, one wide word holding all channels) ***
374	    i_data_ram : entity work.olo_base_ram_sdp
375	        generic map (
376	            Depth_g       => DataMemDepth_c,
377	            Width_g       => InWidth_c * Channels_g,
378	            RdLatency_g   => 1,
379	            RamStyle_g    => DataMemStyle_g,
380	            RamBehavior_g => DataRamBehavior_g
381	        )
382	        port map (
383	            Clk     => Clk,
384	            Rst     => Rst,
385	            Wr_Addr => r.TapWrAddr,
386	            Wr_Ena  => r.Vld(1),
387	            Wr_Data => r.InSig(1),
388	            Rd_Addr => r.TapRdAddr_2,
389	            Rd_Ena  => '1',
390	            Rd_Data => DataRamDout_3
391	        );
392	
393	    -- *** Per-Channel Datapath: one multiplier and one output resize each ***
394	    g_channels : for i in 0 to Channels_g - 1 generate
395	
396	        -- *** Multiplier ***
397	        i_mult : entity work.olo_fix_mult
398	            generic map (
399	                AFmt_g      => InFmt_g,
400	                BFmt_g      => CoefFmt_g,
401	                ResultFmt_g => to_string(MultFmt_c),
402	                Round_g     => FixRound_Trunc_c,
403	                Saturate_g  => FixSaturate_None_c,
404	                OpRegs_g    => MultRegs_g,
405	                RoundReg_g  => "NO",
406	                SatReg_g    => "NO"
407	            )
408	            port map (
409	                Clk        => Clk,
410	                Rst        => Rst,
411	                In_Valid   => r.CalcOn(4),
412	                In_A       => r.MultInTap(i),
413	                In_B       => r.MultInCoef,
414	                Out_Valid  => open,
415	                Out_Result => MultOut_Data(i)
416	            );
417	
418	        -- *** Output Resize (round + saturate accumulator to output format) ***
419	        i_resize : entity work.olo_fix_resize
420	            generic map (
421	                AFmt_g      => to_string(AccuFmt_c),
422	                ResultFmt_g => OutFmt_g,
423	                Round_g     => Round_g,
424	                Saturate_g  => Saturate_g,
425	                RoundReg_g  => "YES",
426	                SatReg_g    => "YES"
427	            )
428	            port map (
429	                Clk        => Clk,
430	                Rst        => Rst,
431	                In_Valid   => r.AccuValid,
432	                In_A       => r.Accu(i),
433	                Out_Valid  => ResizeValidVec(i),
434	                Out_Result => ResizeData(i)
435	            );
436	
437	    end generate;
438	
439	end architecture;
440

