57	        Cfg_WrData   : in    std_logic_vector(fixFmtWidthFromString(Fmt_g) - 1 downto 0) := (others => '0');
58	        Cfg_RdEna    : in    std_logic                                                   := '0';
59	        Cfg_RdData   : out   std_logic_vector(fixFmtWidthFromString(Fmt_g) - 1 downto 0);
60	        Cfg_RdValid  : out   std_logic;
