69	architecture rtl of olo_fix_coef_storage is
70	
71	    -- *** Formats ***
72	    constant Fmt_c : FixFormat_t := cl_fix_format_from_string(Fmt_g);
73	
74	    -- *** Types ***
75	    subtype Data_t is std_logic_vector(fixFmtWidthFromString(Fmt_g) - 1 downto 0);
76	    type DataArray_t is array (natural range <>) of Data_t;
77	
78	    -- *** Functions ***
79	    function initData return DataArray_t is
80	        constant InitReal_c : RealArray_t                   := fromString(Init_g);
81	        variable Data_v     : DataArray_t(0 to Depth_g - 1) := (others => (others => '0'));
82	    begin
83	
84	        -- Initialize elements that have an initializer
85	        for i in 0 to InitReal_c'high loop
86	            Data_v(i) := cl_fix_from_real(InitReal_c(i), Fmt_c);
87	        end loop;
88	
89	        return Data_v;
90	    end function;
91	
92	    -- *** Constants ***
93	    constant EntityName_c : string := "olo_fix_coef_storage";
94	
95	    -- *** Signals ***
96	    signal CoefPipe      : DataArray_t(1 to RdLatency_g);
97	    signal CoefValidPipe : std_logic_vector(1 to RdLatency_g);
98	    attribute shreg_extract of CoefPipe      : signal is ShregExtract_SuppressExtraction_c;
99	    attribute shreg_extract of CoefValidPipe : signal is ShregExtract_SuppressExtraction_c;
100	
101	begin
102	
103	    -- *** Assertions ***
104	    -- synthesis translate_off
105	    assert compareNoCase(StorageType_g, "RAM") or compareNoCase(StorageType_g, "ROM")
106	        report errorMessage(EntityName_c, "Invalid StorageType_g. Allowed values are 'RAM' and 'ROM'.")
107	        severity error;
108	    assert compareNoCase(RamBehavior_g, "RBW") or compareNoCase(RamBehavior_g, "WBR")
109	        report errorMessage(EntityName_c, "Invalid RamBehavior_g. Allowed values are 'RBW' and 'WBR'.")
110	        severity error;
111	    -- synthesis translate_on
112	
113	    -- *** ROM Implementation ***
114	    g_rom : if compareNoCase(StorageType_g, "ROM") generate
115	        -- Implemented as shared variable becaus attributes do not apply properly to constants
116	        shared variable Rom_v : DataArray_t(0 to Depth_g - 1) := initData;
117	
118	        -- Synthesis attributes - control ROM style
119	        attribute rom_style of Rom_v    : variable is MemStyle_g;
120	        attribute romstyle of Rom_v     : variable is MemStyle_g;
121	        attribute syn_romstyle of Rom_v : variable is MemStyle_g;
122	
123	    begin
124	
125	        p_rom : process (Clk) is
126	        begin
127	            if rising_edge(Clk) then
128	                -- Default VAlues
129	                CoefValidPipe(1) <= Coef_RdEna;
130	
131	                -- Read ROM
132	                if Coef_RdEna = '1' then
133	                    CoefPipe(1) <= Rom_v(fromUslv(Coef_Addr));
134	                end if;
135	
136	                -- Read-data pipeline registers
137	                CoefPipe(2 to RdLatency_g)      <= CoefPipe(1 to RdLatency_g-1);
138	                CoefValidPipe(2 to RdLatency_g) <= CoefValidPipe(1 to RdLatency_g-1);
139	
140	                -- Reset
141	                if Rst = '1' then
142	                    CoefValidPipe <= (others => '0');
143	                end if;
144	            end if;
145	        end process;
146	
147	        -- Assign outputs
148	        Coef_RdData  <= CoefPipe(RdLatency_g);
149	        Coef_RdValid <= CoefValidPipe(RdLatency_g);
150	        Cfg_RdData   <= (others => '0');
151	        Cfg_RdValid  <= '0';
152	    end generate;
153	
154	    -- *** RAM Implementation ***
155	    g_ram : if compareNoCase(StorageType_g, "RAM") generate
156	        -- Memory Array
157	        shared variable Ram_v : DataArray_t(0 to Depth_g - 1) := initData;
158	
159	        -- Synthesis attributes - control RAM style
160	        attribute ram_style of Ram_v    : variable is MemStyle_g;
161	        attribute ramstyle of Ram_v     : variable is MemStyle_g;
162	        attribute syn_ramstyle of Ram_v : variable is MemStyle_g;
163	
164	        -- Signals
165	        signal RdPipe      : DataArray_t(1 to RdLatency_g);
166	        signal RdValidPipe : std_logic_vector(1 to RdLatency_g);
167	        attribute shreg_extract of RdValidPipe : signal is ShregExtract_SuppressExtraction_c;
168	        attribute shreg_extract of RdPipe      : signal is ShregExtract_SuppressExtraction_c;
169	
170	    begin
171	
172	        -- Valid signal pipelines
173	        p_valid : process (Clk) is
174	        begin
175	            if rising_edge(Clk) then
176	                -- Default Values
177	                CoefValidPipe(1) <= Coef_RdEna;
178	                if RamReadback_g then
179	                    RdValidPipe(1) <= Cfg_RdEna;
180	                else
181	                    RdValidPipe(1) <= '0';
182	                end if;
183	
184	                -- Pipeline registers
185	                CoefValidPipe(2 to RdLatency_g) <= CoefValidPipe(1 to RdLatency_g-1);
186	                RdValidPipe(2 to RdLatency_g)   <= RdValidPipe(1 to RdLatency_g-1);
187	
188	                -- Reset
189	                if Rst = '1' then
190	                    CoefValidPipe <= (others => '0');
191	                    RdValidPipe   <= (others => '0');
192	                end if;
193	            end if;
194	        end process;
195	
196	        -- RAM implementation
197	        -- Code optimized to be mapped efficiently by all vendors
198	        g_wbr : if compareNoCase(RamBehavior_g, "WBR") generate
199	
200	            p_ram : process (Clk) is
201	            begin
202	                if rising_edge(Clk) then
203	                    -- RAM
204	                    if Cfg_WrEna = '1' then
205	                        Ram_v(fromUslv(Cfg_Addr)) := Cfg_WrData;
206	                    end if;
207	                    RdPipe(1)   <= Ram_v(fromUslv(Cfg_Addr));
208	                    CoefPipe(1) <= Ram_v(fromUslv(Coef_Addr));
209	
210	                    -- Read-data pipeline registers
211	                    RdPipe(2 to RdLatency_g)   <= RdPipe(1 to RdLatency_g-1);
212	                    CoefPipe(2 to RdLatency_g) <= CoefPipe(1 to RdLatency_g-1);
213	                end if;
214	            end process;
215	
216	        end generate;
217	
218	        g_rbw : if compareNoCase(RamBehavior_g, "RBW") generate
219	
220	            p_ram : process (Clk) is
221	            begin
222	                if rising_edge(Clk) then
223	                    -- RAM
224	                    RdPipe(1)   <= Ram_v(fromUslv(Cfg_Addr));
225	                    CoefPipe(1) <= Ram_v(fromUslv(Coef_Addr));
226	                    if Cfg_WrEna = '1' then
227	                        Ram_v(fromUslv(Cfg_Addr)) := Cfg_WrData;
228	                    end if;
229	
230	                    -- Read-data pipeline registers
231	                    RdPipe(2 to RdLatency_g)   <= RdPipe(1 to RdLatency_g-1);
232	                    CoefPipe(2 to RdLatency_g) <= CoefPipe(1 to RdLatency_g-1);
233	                end if;
234	            end process;
235	
236	        end generate;
237	
238	        -- Assign outputs
239	        Cfg_RdData   <= RdPipe(RdLatency_g) when RamReadback_g else (others => '0');
240	        Cfg_RdValid  <= RdValidPipe(RdLatency_g) when RamReadback_g else '0';
241	        Coef_RdData  <= CoefPipe(RdLatency_g);
242	        Coef_RdValid <= CoefValidPipe(RdLatency_g);
243	
244	    end generate;
245	
246	end architecture;
